<?php require_once __DIR__.'/../../backend/shared/auth.php'; require_role('patient'); require_once __DIR__.'/../../backend/shared/layout.php'; $pid=$_SESSION['user']['id'];$d=db()->prepare('SELECT * FROM documents WHERE patient_id=? ORDER BY id DESC');$d->execute([$pid]);$docs=$d->fetchAll(); app_header('เอกสารของฉัน','patient','docs');?><a class="back" href="portal.php">← กลับ</a><div class="card"><h3>เอกสาร PDF</h3><?php foreach($docs as $doc):?><p><a class="btn secondary" href="document-view.php?id=<?=$doc['id']?>"><?=e($doc['title'])?> · <?=e($doc['created_at'])?></a></p><?php endforeach;?><?php if(!$docs):?><p class="tl-meta">ยังไม่มีเอกสาร</p><?php endif;?></div><?php app_footer();?>
